# --- Functions to interact with Kong Admin API ---

def create_resource(resource_type, data, parent_id=None):
    """
    Creates a resource in Kong.
    resource_type: 'services', 'routes', 'upstreams', 'targets'
    data: dictionary of resource properties
    parent_id: For targets, this would be the upstream ID or name.
    """
    url = f"{KONG_ADMIN_URL}/{resource_type}"
    if resource_type == "targets" and parent_id:
        url = f"{KONG_ADMIN_URL}/upstreams/{parent_id}/targets"

    print(f"Attempting to create {resource_type}: {data.get('name') or data.get('target')}")
    try:
        response = requests.post(url, json=data)
        response.raise_for_status()  # Raise an exception for HTTP errors
        print(f"Successfully created {resource_type}: {response.json().get('name') or response.json().get('target')}")
        return response.json()
    except requests.exceptions.HTTPError as e:
        if e.response.status_code == 409:  # Conflict, resource already exists
            print(f"Warning: {resource_type} already exists. Skipping creation. Error: {e.response.json()}")
            # Attempt to fetch the existing resource if it's a service/route/upstream
            if resource_type in ["services", "routes", "upstreams"]:
                name_key = "name"
                existing_url = f"{KONG_ADMIN_URL}/{resource_type}/{data[name_key]}"
                try:
                    existing_response = requests.get(existing_url)
                    existing_response.raise_for_status()
                    print(f"Fetched existing {resource_type}: {existing_response.json().get('name')}")
                    return existing_response.json()
                except requests.exceptions.RequestException as fetch_e:
                    print(f"Error fetching existing {resource_type}: {fetch_e}")
                    return None
            return None
        else:
            print(f"Error creating {resource_type}: {e}")
            print(f"Response content: {e.response.text}")
            return None
    except requests.exceptions.RequestException as e:
        print(f"Network or other error creating {resource_type}: {e}")
        return None

def get_resource_id(resource_type, name):
    """Fetches the ID of a resource by its name."""
    try:
        response = requests.get(f"{KONG_ADMIN_URL}/{resource_type}/{name}")
        response.raise_for_status()
        return response.json().get("id")
    except requests.exceptions.RequestException as e:
        print(f"Error fetching ID for {resource_type} '{name}': {e}")
        return None

