    # 1. Create Upstreams
    created_upstreams = {}
    for upstream_data in UPSTREAMS:
        result = create_resource("upstreams", upstream_data)
        if result:
            created_upstreams[result["name"]] = result["id"]

    # 2. Create Targets
    for target_data in TARGETS:
        upstream_name = target_data.pop("upstream_name")
        if upstream_name in created_upstreams:
            upstream_id = created_upstreams[upstream_name]
            create_resource("targets", target_data, parent_id=upstream_id)
        else:
            print(f"Warning: Upstream '{upstream_name}' not found for target '{target_data.get('target')}'. Skipping.")

    # 3. Create Services
    created_services = {}
    for service_data in SERVICES:
        result = create_resource("services", service_data)
        if result:
            created_services[result["name"]] = result["id"]

    # 4. Create Routes
    for route_data in ROUTES:
        service_name = route_data["service"]["name"]
        if service_name in created_services:
            route_data["service"]["id"] = created_services[service_name]
            create_resource("routes", route_data)
        else:
            print(f"Warning: Service '{service_name}' not found for route '{route_data.get('name')}'. Skipping.")

    print("\nKong configuration script finished.")
